#include <stdio.h>
#include "riscv_nn_convolution.h"

#define INPUT_X 32
#define INPUT_Y 30
#define INPUT_CH 64
#define INPUT_BATCHES 2
#define OUTPUT_CH 16
#define KERNEL_X 3
#define KERNEL_Y 3
#define PAD_X 0
#define PAD_Y 0
#define STRIDE_X 1
#define STRIDE_Y 1
#define OUTPUT_X 30
#define OUTPUT_Y 28
#define OUTPUT_OFFSET 5
#define INPUT_OFFSET 3
#define OUTPUT_ACTIVATION_MIN 0XFFFFFF81
#define OUTPUT_ACTIVATION_MAX 0X0000007E
#define OUTPUT_SHIFT -2
#define OUTPUT_MULT (1<<23)
#define SRC1_LEN (INPUT_BATCHES * INPUT_CH * INPUT_X * INPUT_Y)
#define SRC2_LEN (OUTPUT_CH * INPUT_CH * KERNEL_X * KERNEL_Y)
#define BUF_LEN  (INPUT_CH * KERNEL_X * KERNEL_Y * 2)
#define OUT_LEN  (INPUT_BATCHES * OUTPUT_CH * OUTPUT_X * OUTPUT_Y)

q7_t src1[SRC1_LEN] FUNC_ATTR_ALIGN;
q7_t src2[SRC2_LEN] FUNC_ATTR_ALIGN;
int32_t bias[OUTPUT_CH] FUNC_ATTR_ALIGN;
int32_t output_shift[OUT_LEN] FUNC_ATTR_ALIGN;
int32_t output_mult[OUT_LEN] FUNC_ATTR_ALIGN;
q7_t output[OUT_LEN] FUNC_ATTR_ALIGN;
q15_t in_tmp_buf[BUF_LEN] FUNC_ATTR_ALIGN;
#if !ENA_RANDOM_INPUT
q7_t golden[OUT_LEN];
#endif

int main (void)
{
    enable_fs_and_vs();
    uint32_t retStatus=NDS_SUCCESS;

    uint32_t i;
#if ENA_RANDOM_INPUT
    for(i=0; i<SRC1_LEN; i++)
    {
        src1[i] = rand();
    }
    for(i=0; i<SRC2_LEN; i++)
    {
        src2[i] = rand();
    }
    for(i=0; i<OUTPUT_CH; i++)
    {
        bias[i] = rand();
    }
#else
    FILE *fptr_src1, *fptr_src2, *fptr_bias;
    test_Fopen("8b_in1.bin", "rb", &fptr_src1);
    test_Fopen("8b_in2.bin", "rb", &fptr_src2);
    test_Fopen("32b_in1.bin", "rb", &fptr_bias);
    test_Fread(src1, sizeof(*src1), SRC1_LEN, fptr_src1, "src1");
    test_Fread(src2, sizeof(*src2), SRC2_LEN, fptr_src2, "src2");
    test_Fread(bias, sizeof(*bias), OUTPUT_CH, fptr_bias, "bias");
    fclose(fptr_src1);
    fclose(fptr_src2);
    fclose(fptr_bias);
#endif
    for(i=0; i<OUT_LEN; i++)
    {
        output_shift[i] = OUTPUT_SHIFT;
        output_mult[i] = OUTPUT_MULT;
    }

#ifdef PF_COUNTER
    startPFM;
#endif
    riscv_nn_conv_HWC_s8_s8_s8_asym_bias_any(src1, INPUT_X, INPUT_Y, INPUT_CH, INPUT_BATCHES, src2, OUTPUT_CH, KERNEL_X, KERNEL_Y, PAD_X, PAD_Y, STRIDE_X, STRIDE_Y, bias, output, output_shift, output_mult, OUTPUT_OFFSET, INPUT_OFFSET, OUTPUT_ACTIVATION_MIN, OUTPUT_ACTIVATION_MAX, OUTPUT_X, OUTPUT_Y, in_tmp_buf);
#ifdef PF_COUNTER
    stopPFM;
    readResult();
#endif

#if !ENA_RANDOM_INPUT
    FILE *fptr_golden;
    test_Fopen("convolve_s8_golden3.bin", "rb", &fptr_golden);
    test_Fread(golden, sizeof(*golden), OUT_LEN, fptr_golden, "golden");
    uint32_t maxDiff = verify_buffer(output, golden, OUT_LEN, sizeof(*golden));
    if (maxDiff > 1)
    {
        printf("accuracy checking fail\n\n");
        retStatus |= NDS_FAILURE;
    }
    else
    {
        printf("accuracy checking pass\n\n");
        retStatus |= NDS_SUCCESS;
    }
    fclose(fptr_golden);
#endif

    return retStatus;
}

