q7_t *nn_mat_mult_kernel_s8_offset(const q7_t *input_a,
                                   const q7_t *input_b,
                                   const uint16_t output_ch,
                                   const int32_t *out_shift,
                                   const int32_t *out_mult,
                                   const int32_t input_offset,     //value is in the range of [-127, 128]
                                   const int32_t out_offset,       //value is in the range of [-128, 127]
                                   const int16_t activation_min,
                                   const int16_t activation_max,
                                   const uint16_t num_col_a,
                                   const int32_t *const output_bias,
                                   q7_t *out_0)
{
#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
    /* set up the second output pointers */
    q7_t *out_1 = out_0 + output_ch;
    const int32_t *bias = output_bias;

    long row_count = output_ch >> 1;
    const q7_t *ptr_a0 = input_a;

    long vl;
    long vlenb = NDS_VEC_CSR_GET_VLENB();

    vint32m1_t vZero_e0 = __riscv_vand(__riscv_vundefined_i32m1(), 0, 1);    //const zero for redsum

    /* this loop over rows in A */
    while (row_count)
    {
        vl = __riscv_vsetvl_e8m2(num_col_a);
        vint8m2_t vOne_i8m2 = __riscv_vmv_v_x_i8m2(1, vl);                   //const one

        /* setup pointers for B */
        const q7_t *ptr_b0 = input_b;
        const q7_t *ptr_b1 = ptr_b0 + num_col_a;

        /* align the second pointer for A */
        const q7_t *ptr_a1 = ptr_a0 + num_col_a;

        long col_count = num_col_a;

        // init the accumulator
        vl = __riscv_vsetvl_e32m2(num_col_a);
        vint32m2_t vAcc0 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
        vint32m2_t vAcc1 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
        vint32m2_t vAcc2 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
        vint32m2_t vAcc3 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
        vint32m2_t vAcc_wt_0 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
        vint32m2_t vAcc_wt_1 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);

        while(col_count >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M2))
        {
            vl = __riscv_vsetvl_e8m2(col_count);
            vint8m2_t vA0_i8m2 = __riscv_vle8_v_i8m2(ptr_a0, vl);
            vint8m2_t vA1_i8m2 = __riscv_vle8_v_i8m2(ptr_a1, vl);
            vint8m2_t vB0_i8m2 = __riscv_vle8_v_i8m2(ptr_b0, vl);
            vint8m2_t vB1_i8m2 = __riscv_vle8_v_i8m2(ptr_b1, vl);
            ptr_a0 += vl;
            ptr_a1 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;
            col_count -= vl;

            vl = __riscv_vsetvl_e32m2(vl);
            vAcc0 = __riscv_vd4dots_vv_i32m2_tu(vAcc0, vA0_i8m2, vB0_i8m2, vl);     //ch_0_out_0 += a0 * b0;
            vAcc1 = __riscv_vd4dots_vv_i32m2_tu(vAcc1, vA0_i8m2, vB1_i8m2, vl);     //ch_0_out_1 += a0 * b1;
            vAcc2 = __riscv_vd4dots_vv_i32m2_tu(vAcc2, vA1_i8m2, vB0_i8m2, vl);     //ch_1_out_0 += a1 * b0;
            vAcc3 = __riscv_vd4dots_vv_i32m2_tu(vAcc3, vA1_i8m2, vB1_i8m2, vl);     //ch_1_out_1 += a1 * b1;
            vAcc_wt_0 = __riscv_vd4dots_vv_i32m2_tu(vAcc_wt_0, vA0_i8m2, vOne_i8m2, vl);    //sum_input_a0 += a0;
            vAcc_wt_1 = __riscv_vd4dots_vv_i32m2_tu(vAcc_wt_1, vA1_i8m2, vOne_i8m2, vl);    //sum_input_a1 += a1;
        }

        //extra process for the case of elements to be dot producted is not a mutiple of 4
        if(col_count > 0)
        {
            //clean one of the dot product source
            vl = __riscv_vsetvl_e8m2(col_count+3);
            vint8m2_t vA0_i8m2 = __riscv_vand(__riscv_vundefined_i8m2(), 0, vl);
            vint8m2_t vA1_i8m2 = __riscv_vand(__riscv_vundefined_i8m2(), 0, vl);
            vint8m2_t vB0_i8m2, vB1_i8m2;

            vl = __riscv_vsetvl_e8m2(col_count);
            vA0_i8m2 = __riscv_vle8_v_i8m2_tu(vA0_i8m2, ptr_a0, vl);
            vA1_i8m2 = __riscv_vle8_v_i8m2_tu(vA1_i8m2, ptr_a1, vl);
            vB0_i8m2 = __riscv_vle8_v_i8m2(ptr_b0, vl);
            vB1_i8m2 = __riscv_vle8_v_i8m2(ptr_b1, vl);
            ptr_a0 += vl;
            ptr_a1 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;
            col_count -= vl;

            vl = (vl + 3) >> 2;
            vl = __riscv_vsetvl_e32m2(vl);
            vAcc0 = __riscv_vd4dots_vv_i32m2_tu(vAcc0, vA0_i8m2, vB0_i8m2, vl);     //ch_0_out_0 += a0 * b0;
            vAcc1 = __riscv_vd4dots_vv_i32m2_tu(vAcc1, vA0_i8m2, vB1_i8m2, vl);     //ch_0_out_1 += a0 * b1;
            vAcc2 = __riscv_vd4dots_vv_i32m2_tu(vAcc2, vA1_i8m2, vB0_i8m2, vl);     //ch_1_out_0 += a1 * b0;
            vAcc3 = __riscv_vd4dots_vv_i32m2_tu(vAcc3, vA1_i8m2, vB1_i8m2, vl);     //ch_1_out_1 += a1 * b1;
            vAcc_wt_0 = __riscv_vd4dots_vv_i32m2_tu(vAcc_wt_0, vA0_i8m2, vOne_i8m2, vl);    //sum_input_a0 += a0;
            vAcc_wt_1 = __riscv_vd4dots_vv_i32m2_tu(vAcc_wt_1, vA1_i8m2, vOne_i8m2, vl);    //sum_input_a1 += a1;
        }

        vl = __riscv_vsetvl_e32m2(num_col_a);
        vint32m1_t vSum_e0_0 = __riscv_vundefined_i32m1();
        vint32m1_t vSum_e0_1 = __riscv_vundefined_i32m1();
        vint32m1_t vSum_e0_2 = __riscv_vundefined_i32m1();
        vint32m1_t vSum_e0_3 = __riscv_vundefined_i32m1();
        vint32m1_t vSum_wt_e0_0 = __riscv_vundefined_i32m1();
        vint32m1_t vSum_wt_e0_1 = __riscv_vundefined_i32m1();
        vSum_e0_0 = __riscv_vredsum_tu(vSum_e0_0, vAcc0, vZero_e0, vl);
        vSum_e0_1 = __riscv_vredsum_tu(vSum_e0_1, vAcc1, vZero_e0, vl);
        vSum_e0_2 = __riscv_vredsum_tu(vSum_e0_2, vAcc2, vZero_e0, vl);
        vSum_e0_3 = __riscv_vredsum_tu(vSum_e0_3, vAcc3, vZero_e0, vl);
        vSum_wt_e0_0 = __riscv_vredsum_tu(vSum_wt_e0_0, vAcc_wt_0, vZero_e0, vl);
        vSum_wt_e0_1 = __riscv_vredsum_tu(vSum_wt_e0_1, vAcc_wt_1, vZero_e0, vl);

        vl = __riscv_vsetvl_e32m1(2);
        vSum_e0_0 = __riscv_vslideup(vSum_e0_0, vSum_e0_2, 1, vl);
        vSum_e0_1 = __riscv_vslideup(vSum_e0_1, vSum_e0_3, 1, vl);
        vSum_wt_e0_0 = __riscv_vslideup(vSum_wt_e0_0, vSum_wt_e0_1, 1, vl);

        //add input_offset back
        vSum_e0_0 = __riscv_vmacc(vSum_e0_0, input_offset, vSum_wt_e0_0, vl);
        vSum_e0_1 = __riscv_vmacc(vSum_e0_1, input_offset, vSum_wt_e0_0, vl);

        //add bias back
        if (bias)
        {
            vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
            bias += vl;
            vSum_e0_0 = __riscv_vadd(vSum_e0_0, vBias, vl);
            vSum_e0_1 = __riscv_vadd(vSum_e0_1, vBias, vl);
        }

        //===== Quantize down =====
        vuint32m1_t vShf = __riscv_vle32_v_u32m1((u32_t*)out_shift, vl);
        vint32m1_t vMul = __riscv_vle32_v_i32m1(out_mult, vl);
        vShf = __riscv_vrsub(vShf, 30, vl);

        vint64m2_t vSum_i64_0 = __riscv_vwmul(vSum_e0_0, vMul, vl);
        vint64m2_t vSum_i64_1 = __riscv_vwmul(vSum_e0_1, vMul, vl);
        vSum_e0_0 = __riscv_vnsra(vSum_i64_0, vShf, vl);
        vSum_e0_1 = __riscv_vnsra(vSum_i64_1, vShf, vl);
        vSum_e0_0 = __riscv_vssra(vSum_e0_0, 1, __RISCV_VXRM_RNU, vl);
        vSum_e0_1 = __riscv_vssra(vSum_e0_1, 1, __RISCV_VXRM_RNU, vl);

        // Add offset
        vSum_e0_0 = __riscv_vadd(vSum_e0_0, out_offset, vl);
        vSum_e0_1 = __riscv_vadd(vSum_e0_1, out_offset, vl);

        // Clamp the result
        vSum_e0_0 = __riscv_vmax(vSum_e0_0, activation_min, vl);
        vSum_e0_0 = __riscv_vmin(vSum_e0_0, activation_max, vl);
        vSum_e0_1 = __riscv_vmax(vSum_e0_1, activation_min, vl);
        vSum_e0_1 = __riscv_vmin(vSum_e0_1, activation_max, vl);

        //narrowing and store the results
        vint16mf2_t vSum_i16_0 = __riscv_vnsra(vSum_e0_0, 0, vl);
        vint16mf2_t vSum_i16_1 = __riscv_vnsra(vSum_e0_1, 0, vl);
        vint8mf4_t vSum_i8_0 = __riscv_vnsra(vSum_i16_0, 0, vl);
        vint8mf4_t vSum_i8_1 = __riscv_vnsra(vSum_i16_1, 0, vl);
        __riscv_vse8(out_0, vSum_i8_0, vl);
        __riscv_vse8(out_1, vSum_i8_1, vl);
        out_0 += vl;
        out_1 += vl;
        out_mult += vl;
        out_shift += vl;

        /* skip row */
        ptr_a0 += num_col_a;
        row_count--;
    }

    /* compute the last odd numbered row if any */
    if (output_ch & 0x1)
    {
        vl = __riscv_vsetvl_e8m4(num_col_a);
        vint8m4_t vOne_i8m4 = __riscv_vmv_v_x_i8m4(1, vl);                   //const one

        /* setup pointers for B */
        const q7_t *ptr_b0 = input_b;
        const q7_t *ptr_b1 = ptr_b0 + num_col_a;

        q31_t sum_input_a0 = 0;
        long col_count = num_col_a;

        // init the accumulator
        vl = __riscv_vsetvl_e32m4(num_col_a);
        vint32m4_t vAcc0 = __riscv_vand(__riscv_vundefined_i32m4(), 0, vl);
        vint32m4_t vAcc1 = __riscv_vand(__riscv_vundefined_i32m4(), 0, vl);
        vint32m4_t vAcc_wt = __riscv_vand(__riscv_vundefined_i32m4(), 0, vl);

        while(col_count >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M4))
        {
            vl = __riscv_vsetvl_e8m4(col_count);
            vint8m4_t vA0_i8m4 = __riscv_vle8_v_i8m4(ptr_a0, vl);
            vint8m4_t vB0_i8m4 = __riscv_vle8_v_i8m4(ptr_b0, vl);
            vint8m4_t vB1_i8m4 = __riscv_vle8_v_i8m4(ptr_b1, vl);
            col_count -= vl;
            ptr_a0 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;

            vl = __riscv_vsetvl_e32m4(vl);
            vAcc0 = __riscv_vd4dots_vv_i32m4_tu(vAcc0, vA0_i8m4, vB0_i8m4, vl);
            vAcc1 = __riscv_vd4dots_vv_i32m4_tu(vAcc1, vA0_i8m4, vB1_i8m4, vl);
            vAcc_wt = __riscv_vd4dots_vv_i32m4_tu(vAcc_wt, vA0_i8m4, vOne_i8m4, vl);
        }

        if(col_count > 0)
        {
            //clean one of the dot product source
            vl = __riscv_vsetvl_e8m4(col_count+3);
            vint8m4_t vA0_i8m4 = __riscv_vand(__riscv_vundefined_i8m4(), 0, vl);
            vint8m4_t vB0_i8m4, vB1_i8m4;

            vl = __riscv_vsetvl_e8m4(col_count);
            vA0_i8m4 = __riscv_vle8_v_i8m4_tu(vA0_i8m4, ptr_a0, vl);
            vB0_i8m4 = __riscv_vle8_v_i8m4(ptr_b0, vl);
            vB1_i8m4 = __riscv_vle8_v_i8m4(ptr_b1, vl);
            col_count -= vl;
            ptr_a0 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;

            vl = (vl + 3) >> 2;
            vl = __riscv_vsetvl_e32m4(vl);
            vAcc0 = __riscv_vd4dots_vv_i32m4_tu(vAcc0, vA0_i8m4, vB0_i8m4, vl);
            vAcc1 = __riscv_vd4dots_vv_i32m4_tu(vAcc1, vA0_i8m4, vB1_i8m4, vl);
            vAcc_wt = __riscv_vd4dots_vv_i32m4_tu(vAcc_wt, vA0_i8m4, vOne_i8m4, vl);
        }

        vl = __riscv_vsetvl_e32m4(num_col_a);       //note the avl here
        vint32m1_t vSum_e0_0 = __riscv_vundefined_i32m1();
        vint32m1_t vSum_e0_1 = __riscv_vundefined_i32m1();
        vint32m1_t vSum_wt_e0 = __riscv_vundefined_i32m1();
        vSum_e0_0 = __riscv_vredsum_tu(vSum_e0_0, vAcc0, vZero_e0, vl);
        vSum_e0_1 = __riscv_vredsum_tu(vSum_e0_1, vAcc1, vZero_e0, vl);
        vSum_wt_e0 = __riscv_vredsum_tu(vSum_wt_e0, vAcc_wt, vZero_e0, vl);

        sum_input_a0 = __riscv_vmv_x(vSum_wt_e0);
        sum_input_a0 *= input_offset;

        vl = __riscv_vsetvl_e32m1(2);
        vSum_e0_0 = __riscv_vslideup(vSum_e0_0, vSum_e0_1, 1, vl);

        //add input_offset back
        vSum_e0_0 = __riscv_vadd(vSum_e0_0, sum_input_a0, vl);

        //add bias back
        if (bias)
        {
            long bias_val = *bias++;
            vSum_e0_0 = __riscv_vadd(vSum_e0_0, bias_val, vl);
        }

        //===== Quantize down =====
        long out_mult_val = *out_mult,
             out_shift_val = 30 - *out_shift;

        vint64m2_t vSum_i64 = __riscv_vwmul(vSum_e0_0, out_mult_val, vl);
        vSum_e0_0 = __riscv_vnsra(vSum_i64, out_shift_val, vl);
        vSum_e0_0 = __riscv_vssra(vSum_e0_0, 1, __RISCV_VXRM_RNU, vl);

        // Add offset
        vSum_e0_0 = __riscv_vadd(vSum_e0_0, out_offset, vl);

        // Clamp the result
        vSum_e0_0 = __riscv_vmax(vSum_e0_0, activation_min, vl);
        vSum_e0_0 = __riscv_vmin(vSum_e0_0, activation_max, vl);

        //narrowing and store the results
        vint16mf2_t vSum_i16 = __riscv_vnsra(vSum_e0_0, 0, vl);
        vint8mf4_t vSum_i8 = __riscv_vnsra(vSum_i16, 0, vl);
        __riscv_vsse8(out_0, output_ch, vSum_i8, vl);
        out_0++;
        out_mult++;
        out_shift++;
    }

    out_0 += output_ch;

    /* return the new output pointer with offset */
    return out_0;
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
    /* set up the second output pointers */
    q7_t *out_1 = out_0 + output_ch;
    const int32_t *bias = output_bias;

    long row_count = output_ch >> 1;
    const q7_t *ptr_a0 = input_a;

    long vl;
    long vlenb = NDS_VEC_CSR_GET_VLENB();

#if (__clang__)
    register const long zero asm ("x0") = 0;
#else
    register const long zero asm ("x0");
#endif

