1753	    for (long cur_row = 0; (cur_row + 2) <= out_tensor_ch; cur_row += 2)
1754	    {
1755	        /* setup pointers for B */
1756	        const int8_t *ptr_b0 = input_b;
1757	        const int8_t *ptr_b1 = ptr_b0 + num_col_a;
1758	
1759	        /* align the second pointer for A */
1760	        const int8_t *ptr_a1 = ptr_a0 + num_col_a;
1761	
1762	        //init the accumulator
1763	        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
1764	        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
1765	        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
1766	        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
1767	        NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
1768	
1769	        long col_count = num_col_a;
1770	        while(col_count >= maxvl_per_loop)
1771	        {
1772	            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
1773	            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
1774	            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
1775	            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
1776	            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a1);
1777	            ptr_a0 += vl;
1778	            ptr_a1 += vl;
1779	            ptr_b0 += vl;
1780	            ptr_b1 += vl;
1781	            col_count -= vl;
1782	
1783	            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
1784	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);   //ch_0_out_0 += a0 * b0;
1785	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);   //ch_0_out_1 += a0 * b1;
1786	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V20, NDS_VEC_V24);   //ch_1_out_0 += a1 * b0;
1787	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V20, NDS_VEC_V28);  //ch_1_out_1 += a1 * b1;
1788	        }
1789	
1790	        //extra process for the case of elements to be dot producted is not a mutiple of 4
1791	        if(col_count > 0)
1792	        {
1793	            //clean one of the dot product source
1794	            long tmp_avl;
1795	            tmp_avl = col_count + 3;
1796	            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
1797	            NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);
1798	            NDS_VEC_VAND_VI(NDS_VEC_V28, NDS_VEC_V28, 0);
1799	
1800	            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
1801	            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
1802	            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
1803	            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
1804	            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a1);
1805	            ptr_a0 += vl;
1806	            ptr_a1 += vl;
1807	            ptr_b0 += vl;
1808	            ptr_b1 += vl;
1809	            col_count -= vl;
1810	
1811	            vl = (vl + 3) >> 2;
1812	            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
1813	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);   //ch_0_out_0 += a0 * b0;
1814	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);   //ch_0_out_1 += a0 * b1;
1815	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V20, NDS_VEC_V24);   //ch_1_out_0 += a1 * b0;
1816	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V20, NDS_VEC_V28);  //ch_1_out_1 += a1 * b1;
1817	        }
1818	
1819	        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1820	        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
1821	        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);   //note the avl here
1822	        NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);    //ch_0_out_0
1823	        NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V4, NDS_VEC_V31);    //ch_0_out_1
1824	        NDS_VEC_VREDSUM_VS(NDS_VEC_V2, NDS_VEC_V8, NDS_VEC_V31);    //ch_1_out_0
1825	        NDS_VEC_VREDSUM_VS(NDS_VEC_V3, NDS_VEC_V12, NDS_VEC_V31);   //ch_1_out_1
1826	
1827	        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1828	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V2, 1);
1829	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V1, NDS_VEC_V3, 1);
1830	
1831	        //add extra contribution back
1832	        NDS_VEC_VLE32_V(NDS_VEC_V4, contri_buf);
1833	        contri_buf += vl;
1834	        NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);
1835	        NDS_VEC_VADD_VV(NDS_VEC_V1, NDS_VEC_V1, NDS_VEC_V4);
1836	
1837	        //===== Quantize down =====
1838	        NDS_VEC_VLE32_V(NDS_VEC_V2, out_shift);
1839	        NDS_VEC_VLE32_V(NDS_VEC_V3, out_scale);
1840	        NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);
1841	
1842	        NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V0, NDS_VEC_V3);
1843	        NDS_VEC_VWMUL_VV(NDS_VEC_V6, NDS_VEC_V1, NDS_VEC_V3);
1844	        NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
1845	        NDS_VEC_VNSRA_WV(NDS_VEC_V6, NDS_VEC_V6, NDS_VEC_V2);
1846	        NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);
1847	        NDS_VEC_VSSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 1);
1848	
1849	        // Add offset
1850	        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);
1851	        NDS_VEC_VADD_VX(NDS_VEC_V6, NDS_VEC_V6, out_offset);
1852	
1853	        // Clamp the result
1854	        NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, act_min);
1855	        NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);
1856	        NDS_VEC_VMAX_VX(NDS_VEC_V6, NDS_VEC_V6, act_min);
1857	        NDS_VEC_VMIN_VX(NDS_VEC_V6, NDS_VEC_V6, act_max);
1858	
1859	        //narrowing and store the results
1860	        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
1861	        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
1862	        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
1863	        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
1864	        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
1865	        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
1866	        NDS_VEC_VSE8_V(NDS_VEC_V4, out_0);
1867	        NDS_VEC_VSE8_V(NDS_VEC_V6, out_1);
1868	        out_0 += vl;
1869	        out_1 += vl;
1870	        out_scale += vl;
1871	        out_shift += vl;
1872	
1873	        ptr_a0 += num_col_a;
1874	    }
1875	
1876	    /* compute the last odd numbered row if any */
1877	    if (out_tensor_ch & 0x1)
1878	    {
1879	        /* setup pointers for B */
1880	        const int8_t *ptr_b0 = input_b;
1881	        const int8_t *ptr_b1 = ptr_b0 + num_col_a;
1882	
1883	        const long load_stride_byte = 0;
1884	        const long store_stride_byte = sizeof(*out) * out_tensor_ch;
1885	
1886	        //init the accumulator
1887	        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
1888	        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
1889	        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
1890	
1891	        long col_count = num_col_a;
